function ThemeToggle() {
  const { theme, toggleTheme } = useContext(ThemeContext);

  return (
    <button
      onClick={toggleTheme}
      aria-label="Toggle theme"
      className="fixed top-4 right-4 z-50 flex items-center justify-center w-10 h-10 rounded-full bg-[var(--accent-bg)] text-[var(--primary-color)] hover:bg-[var(--hover-bg)] hover:text-white transition focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[var(--primary-color)]"
      title={`Переключить тему: ${theme === "dark" ? "Тёмная" : "Светлая"}`}
    >
      {theme === "dark" ? <Sun size={20} /> : <Moon size={20} />}
    </button>
  );
}

